const now = new Date();
const year = now.getFullYear();
const month = now.getMonth();

// Find first weekday of current month
let firstBizDay = new Date(year, month, 1);
const dayOfWeek = firstBizDay.getDay();
if (dayOfWeek === 0) firstBizDay.setDate(2);
if (dayOfWeek === 6) firstBizDay.setDate(3);

// Skip New Year's Day (Jan 1 on weekday -> Jan 2)
if (month === 0 && firstBizDay.getDate() === 1) {
  firstBizDay.setDate(2);
  if (firstBizDay.getDay() === 0) firstBizDay.setDate(3);
  if (firstBizDay.getDay() === 6) firstBizDay.setDate(4);
}

const isFirstBizDay = now.getDate() === firstBizDay.getDate()
  && now.getMonth() === firstBizDay.getMonth();

if (!isFirstBizDay) {
  return [{ json: { is_first_biz_day: false } }];
}

// Target month is previous month
const targetDate = new Date(year, month - 1, 1);
const targetMonth = targetDate.toISOString().slice(0, 10);
const reportLabel = targetDate.toLocaleString('en-US', { month: 'long', year: 'numeric' });

return [{
  json: {
    is_first_biz_day: true,
    target_month: targetMonth,
    report_label: reportLabel,
    fiscal_year: targetDate.getFullYear()
  }
}];

const body = $input.first().json.body || $input.first().json;
let targetMonth, reportLabel, fiscalYear;

if (body.month) {
  const d = new Date(body.month + 'T00:00:00Z');
  targetMonth = d.toISOString().slice(0, 10);
  reportLabel = d.toLocaleString('en-US', { month: 'long', year: 'numeric', timeZone: 'UTC' });
  fiscalYear = d.getUTCFullYear();
} else {
  const now = new Date();
  const d = new Date(now.getFullYear(), now.getMonth() - 1, 1);
  targetMonth = d.toISOString().slice(0, 10);
  reportLabel = d.toLocaleString('en-US', { month: 'long', year: 'numeric' });
  fiscalYear = d.getFullYear();
}

return [{
  json: {
    is_first_biz_day: true,
    target_month: targetMonth,
    report_label: reportLabel,
    fiscal_year: fiscalYear
  }
}];

const actualsArr = $('Get Financial Actuals').first().json;
const budgetArr = $('Get Budget Baseline').first().json;
const ytdArr = $('Get YTD Actuals').all().map(i => i.json);
const prevArr = $('Get Previous Month').first().json;
const mergeData = $('Merge Target Month').first().json;

// Handle Supabase REST response (returns array)
const actuals = Array.isArray(actualsArr) ? actualsArr[0] : actualsArr;
const budget = Array.isArray(budgetArr) ? budgetArr[0] : budgetArr;
const ytdActuals = Array.isArray(ytdArr[0]) ? ytdArr[0] : ytdArr;
const prevMonth = Array.isArray(prevArr) ? prevArr[0] : prevArr;

const targetMonth = mergeData.target_month;
const reportLabel = mergeData.report_label;
const fiscalYear = mergeData.fiscal_year;

if (!actuals || (Array.isArray(actualsArr) && actualsArr.length === 0)) {
  return [{ json: { has_data: false, target_month: targetMonth, report_label: reportLabel, fiscal_year: fiscalYear } }];
}

// Parse budget JSONB fields
const revenueMix = typeof budget.revenue_mix === 'string' ? JSON.parse(budget.revenue_mix) : budget.revenue_mix;
const expenseCats = typeof budget.expense_categories === 'string' ? JSON.parse(budget.expense_categories) : budget.expense_categories;

// Revenue calculations
const totalRevenue = Number(actuals.revenue_residential || 0) + Number(actuals.revenue_commercial || 0)
  + Number(actuals.revenue_retainer || 0) + Number(actuals.revenue_other || 0);
const budgetMonthlyRevenue = Number(budget.monthly_revenue_avg);

const revenueByStream = {
  residential: {
    actual: Number(actuals.revenue_residential || 0),
    budget: budgetMonthlyRevenue * (revenueMix.residential?.pct || 0.80),
    variance_pct: 0
  },
  commercial: {
    actual: Number(actuals.revenue_commercial || 0),
    budget: budgetMonthlyRevenue * (revenueMix.commercial?.pct || 0.15),
    variance_pct: 0
  },
  retainer: {
    actual: Number(actuals.revenue_retainer || 0),
    budget: budgetMonthlyRevenue * (revenueMix.retainer?.pct || 0.05),
    variance_pct: 0
  },
  other: {
    actual: Number(actuals.revenue_other || 0),
    budget: 0,
    variance_pct: 0
  }
};

for (const [key, stream] of Object.entries(revenueByStream)) {
  if (stream.budget > 0) {
    stream.variance_pct = Number(((stream.actual - stream.budget) / stream.budget * 100).toFixed(1));
  }
}

// Expense calculations with 15% variance flagging
const expenseCategories = ['equipment', 'software', 'insurance', 'marketing', 'vehicle', 'professional', 'contractor', 'misc'];
const monthlyExpenseBudget = {};
for (const cat of expenseCategories) {
  monthlyExpenseBudget[cat] = (expenseCats[cat] || 0) / 12;
}

const expenses = {};
let totalExpenses = 0;
const flaggedCategories = [];
for (const cat of expenseCategories) {
  const actual = Number(actuals['expense_' + cat] || 0);
  const budgetAmt = monthlyExpenseBudget[cat];
  const variancePct = budgetAmt > 0 ? ((actual - budgetAmt) / budgetAmt * 100) : 0;
  expenses[cat] = { actual, budget: Number(budgetAmt.toFixed(2)), variance_pct: Number(variancePct.toFixed(1)) };
  totalExpenses += actual;
  if (variancePct > 15) {
    flaggedCategories.push({ category: cat, variance_pct: Number(variancePct.toFixed(1)), actual, budget: Number(budgetAmt.toFixed(2)) });
  }
}

// Profitability
const netIncome = totalRevenue - totalExpenses;
const netMargin = totalRevenue > 0 ? Number((netIncome / totalRevenue * 100).toFixed(1)) : 0;
const marginTarget = 35;
const breakEvenJobs = 20;

// YTD calculations
let ytdRevenue = 0, ytdExpenses = 0, ytdJobs = 0;
const ytdRows = Array.isArray(ytdActuals) ? ytdActuals : [];
for (const row of ytdRows) {
  ytdRevenue += Number(row.revenue_residential || 0) + Number(row.revenue_commercial || 0)
    + Number(row.revenue_retainer || 0) + Number(row.revenue_other || 0);
  for (const cat of expenseCategories) {
    ytdExpenses += Number(row['expense_' + cat] || 0);
  }
  ytdJobs += Number(row.jobs_completed || 0);
}

// Cash position (monthly snapshot approach)
const startingCash = 0; // First month default; no running balance table
const endingCash = startingCash + totalRevenue - totalExpenses;
const daysInMonth = new Date(
  new Date(targetMonth + 'T00:00:00Z').getUTCFullYear(),
  new Date(targetMonth + 'T00:00:00Z').getUTCMonth() + 1, 0
).getDate();
const monthlyBurnRate = totalExpenses;

// MoM trend
let momTrend = { prev_revenue: 0, curr_revenue: totalRevenue, direction: 'flat', change_pct: 0 };
if (prevMonth && !Array.isArray(prevMonth)) {
  const prevRev = Number(prevMonth.revenue_residential || 0) + Number(prevMonth.revenue_commercial || 0)
    + Number(prevMonth.revenue_retainer || 0) + Number(prevMonth.revenue_other || 0);
  momTrend.prev_revenue = prevRev;
  if (prevRev > 0) {
    const changePct = ((totalRevenue - prevRev) / prevRev * 100);
    momTrend.change_pct = Number(changePct.toFixed(1));
    momTrend.direction = changePct > 2 ? 'up' : (changePct < -2 ? 'down' : 'flat');
  }
}

return [{
  json: {
    has_data: true,
    target_month: targetMonth,
    report_label: reportLabel,
    fiscal_year: fiscalYear,
    raw_actuals: actuals,
    metrics: {
      total_revenue: totalRevenue,
      total_expenses: totalExpenses,
      revenue_by_stream: revenueByStream,
      expenses_by_category: expenses,
      flagged_categories: flaggedCategories,
      jobs_completed: Number(actuals.jobs_completed || 0),
      avg_job_value: Number(actuals.jobs_completed) > 0 ? Number((totalRevenue / Number(actuals.jobs_completed)).toFixed(2)) : 0,
      net_income: netIncome,
      net_margin: netMargin,
      margin_target: marginTarget,
      break_even_jobs: breakEvenJobs,
      break_even_status: Number(actuals.jobs_completed) >= breakEvenJobs ? 'above' : 'below',
      cash: { starting: startingCash, revenue_in: totalRevenue, expenses_out: totalExpenses, ending: endingCash, monthly_burn: monthlyBurnRate },
      ytd: { revenue: ytdRevenue, expenses: ytdExpenses, jobs: ytdJobs, net_income: ytdRevenue - ytdExpenses },
      budget: { monthly_revenue: budgetMonthlyRevenue, monthly_expense: Number(budget.monthly_expense_avg), monthly_jobs: Number(budget.monthly_jobs_avg) },
      mom_trend: momTrend
    }
  }
}];

const targetMonth = $json.target_month;
const reportLabel = $json.report_label;
const fiscalYear = $json.fiscal_year;

const logEntry = {
  agent_name: 'financial_analyst',
  event_type: 'reminder',
  summary: 'No financial data found for ' + reportLabel + '. Data entry required.',
  data_snapshot: { target_month: targetMonth, reason: 'no_data' },
  quarter: 'Q' + (Math.floor(new Date(targetMonth + 'T00:00:00Z').getUTCMonth() / 3) + 1),
  fiscal_year: fiscalYear
};

const emailHtml = '<h2>Financial Data Needed</h2>' +
  '<p>No financial data was found in the <code>financial_actuals</code> table for <strong>' + reportLabel + '</strong>.</p>' +
  '<p>Please enter the monthly financial data so the Financial Analyst agent can generate your report.</p>' +
  '<p>Once data is entered, you can trigger a report manually via the webhook.</p>';

return [{
  json: {
    log_entry: logEntry,
    email_html: emailHtml,
    report_label: reportLabel,
    target_month: targetMonth
  }
}];

const m = $json.metrics;
const raw = $json.raw_actuals;
const reportLabel = $json.report_label;
const fiscalYear = $json.fiscal_year;
const targetMonth = $json.target_month;

const systemPrompt = `You are a financial analyst for Faith & Harmony LLC (DBA Sentinel Aerial Inspections), a drone services company. Generate a monthly financial summary report as structured JSON.

Writing standards:
- Active voice throughout
- No dashes (use commas or periods instead)
- Direct, conversational tone
- No marketing fluff or corporate jargon
- Be specific with numbers (always include dollar amounts and percentages)

Output format: Return ONLY valid JSON with this exact structure:
{
  "revenue_summary": {
    "heading": "Revenue Summary",
    "narrative": "2-3 paragraphs comparing actual vs budget by revenue stream",
    "mom_trend": "One sentence on month-over-month direction",
    "ytd_status": "One sentence on year-to-date cumulative vs annual target"
  },
  "job_volume": {
    "heading": "Job Volume",
    "narrative": "2 paragraphs on job count, average value, mix shift toward commercial"
  },
  "expense_summary": {
    "heading": "Expense Summary",
    "narrative": "2-3 paragraphs with category breakdown",
    "flagged_variances": "Paragraph specifically addressing any categories exceeding 15% of budget (or 'All expense categories are within 15% of budget.')"
  },
  "profitability": {
    "heading": "Profitability",
    "narrative": "2 paragraphs on net income, margin vs 35% target, break-even status vs 20 jobs"
  },
  "cash_position": {
    "heading": "Cash Position",
    "narrative": "1-2 paragraphs: starting cash, revenue in, expenses out, ending cash, burn rate"
  },
  "outlook": {
    "heading": "Outlook",
    "narrative": "2-3 paragraphs of forward-looking commentary",
    "risks": ["risk 1", "risk 2"],
    "opportunities": ["opportunity 1"]
  },
  "email_summary": "Exactly two sentences summarizing the month's financial performance for email body"
}

IMPORTANT: Use ONLY the numbers provided below. Do not calculate or estimate any figures. All math has been pre-calculated for you.`;

// Build the user prompt with all pre-calculated metrics
const revStreams = m.revenue_by_stream;
const expCats = m.expenses_by_category;
const flagged = m.flagged_categories;
const cash = m.cash;
const ytd = m.ytd;
const budget = m.budget;
const mom = m.mom_trend;

let flaggedText = 'None. All categories are within 15% of budget.';
if (flagged.length > 0) {
  flaggedText = flagged.map(f => `${f.category}: $${f.actual.toLocaleString()} actual vs $${f.budget.toLocaleString()} budget (${f.variance_pct}% over)`).join('; ');
}

const userPrompt = `Generate the financial summary report for ${reportLabel} (Fiscal Year ${fiscalYear}).

REVENUE:
- Total Revenue: $${m.total_revenue.toLocaleString()}
- Budget Target: $${budget.monthly_revenue.toLocaleString()}/month
- Residential: $${revStreams.residential.actual.toLocaleString()} actual vs $${revStreams.residential.budget.toLocaleString()} budget (${revStreams.residential.variance_pct}% variance)
- Commercial: $${revStreams.commercial.actual.toLocaleString()} actual vs $${revStreams.commercial.budget.toLocaleString()} budget (${revStreams.commercial.variance_pct}% variance)
- Retainer: $${revStreams.retainer.actual.toLocaleString()} actual vs $${revStreams.retainer.budget.toLocaleString()} budget (${revStreams.retainer.variance_pct}% variance)
- Other: $${revStreams.other.actual.toLocaleString()}
- MoM Trend: ${mom.direction} (${mom.change_pct}% change from $${mom.prev_revenue.toLocaleString()} previous month)
- YTD Revenue: $${ytd.revenue.toLocaleString()}

JOB VOLUME:
- Jobs Completed: ${m.jobs_completed}
- Budget Target: ${budget.monthly_jobs} jobs/month
- Average Job Value: $${m.avg_job_value}
- Break-even Threshold: ${m.break_even_jobs} jobs
- Break-even Status: ${m.break_even_status}
- YTD Jobs: ${ytd.jobs}

EXPENSES:
- Total Expenses: $${m.total_expenses.toLocaleString()}
- Budget Target: $${budget.monthly_expense.toLocaleString()}/month
${Object.entries(expCats).map(([cat, v]) => `- ${cat}: $${v.actual.toLocaleString()} actual vs $${v.budget.toLocaleString()} budget (${v.variance_pct}% variance)`).join('\n')}
- Flagged Categories (>15% over budget): ${flaggedText}

PROFITABILITY:
- Net Income: $${m.net_income.toLocaleString()}
- Net Margin: ${m.net_margin}%
- Margin Target: ${m.margin_target}%
- YTD Net Income: $${ytd.net_income.toLocaleString()}

CASH POSITION:
- Starting Cash: $${cash.starting.toLocaleString()}
- Revenue In: $${cash.revenue_in.toLocaleString()}
- Expenses Out: $${cash.expenses_out.toLocaleString()}
- Ending Cash: $${cash.ending.toLocaleString()}
- Monthly Burn Rate: $${cash.monthly_burn.toLocaleString()}

Note: Starting cash balance assumes $0 for the first reporting period.

Use ONLY the numbers provided. Do not calculate or estimate any figures.`;

return [{
  json: {
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
    target_month: targetMonth,
    report_label: reportLabel,
    fiscal_year: fiscalYear,
    raw_actuals: raw,
    metrics: m
  }
}];

const response = $json;
const prevData = $('Prepare Claude Prompt').first().json;

let reportJson;
let isValid = true;
let errorMsg = '';

try {
  // Extract text from Claude API response
  const text = response.content[0].text;

  // Try to parse JSON from the response (handle potential markdown code blocks)
  let jsonStr = text.trim();
  if (jsonStr.startsWith('```')) {
    jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
  }

  reportJson = JSON.parse(jsonStr);

  // Validate all 6 required sections exist
  const requiredSections = ['revenue_summary', 'job_volume', 'expense_summary', 'profitability', 'cash_position', 'outlook'];
  const missingSections = requiredSections.filter(s => !reportJson[s]);
  if (missingSections.length > 0) {
    isValid = false;
    errorMsg = 'Missing sections: ' + missingSections.join(', ');
  }

  // Validate email_summary exists
  if (!reportJson.email_summary) {
    isValid = false;
    errorMsg = (errorMsg ? errorMsg + '. ' : '') + 'Missing email_summary field';
  }

  // Validate each section has required fields
  for (const section of requiredSections) {
    if (reportJson[section] && !reportJson[section].narrative) {
      isValid = false;
      errorMsg = (errorMsg ? errorMsg + '. ' : '') + section + ' missing narrative field';
    }
  }
} catch (e) {
  isValid = false;
  errorMsg = 'Failed to parse Claude response as JSON: ' + e.message;
  reportJson = null;
}

return [{
  json: {
    is_valid: isValid,
    error_message: errorMsg,
    claude_response: reportJson,
    target_month: prevData.target_month,
    report_label: prevData.report_label,
    fiscal_year: prevData.fiscal_year,
    raw_actuals: prevData.raw_actuals,
    metrics: prevData.metrics
  }
}];

const { Document, Packer, Paragraph, HeadingLevel, AlignmentType } = require('docx');

const report = $json.claude_response;
const reportLabel = $json.report_label;
const targetMonth = $json.target_month;

// Build document sections
const children = [];

// Title
children.push(new Paragraph({
  text: 'Financial Summary: ' + reportLabel,
  heading: HeadingLevel.HEADING_1,
  alignment: AlignmentType.CENTER
}));

children.push(new Paragraph({
  text: 'Faith & Harmony LLC | Generated ' + new Date().toLocaleDateString('en-US'),
  alignment: AlignmentType.CENTER
}));

children.push(new Paragraph({ text: '' }));

// Add each section
const sections = ['revenue_summary', 'job_volume', 'expense_summary', 'profitability', 'cash_position', 'outlook'];

for (const sectionKey of sections) {
  const section = report[sectionKey];
  children.push(new Paragraph({
    text: section.heading,
    heading: HeadingLevel.HEADING_2
  }));

  // Split narrative into paragraphs
  const paragraphs = section.narrative.split('\n\n');
  for (const p of paragraphs) {
    if (p.trim()) {
      children.push(new Paragraph({ text: p.trim() }));
    }
  }

  // Add MoM trend and YTD status for revenue summary
  if (sectionKey === 'revenue_summary') {
    if (section.mom_trend) {
      children.push(new Paragraph({ text: '' }));
      children.push(new Paragraph({ text: section.mom_trend }));
    }
    if (section.ytd_status) {
      children.push(new Paragraph({ text: section.ytd_status }));
    }
  }

  // Add flagged variances for expense section (bold)
  if (sectionKey === 'expense_summary' && section.flagged_variances) {
    children.push(new Paragraph({ text: '' }));
    children.push(new Paragraph({
      children: [new (require('docx').TextRun)({ text: section.flagged_variances, bold: true })]
    }));
  }

  // Add risks and opportunities for outlook
  if (sectionKey === 'outlook') {
    if (section.risks && section.risks.length > 0) {
      children.push(new Paragraph({ text: 'Risks:', heading: HeadingLevel.HEADING_3 }));
      for (const risk of section.risks) {
        children.push(new Paragraph({
          text: risk,
          bullet: { level: 0 }
        }));
      }
    }
    if (section.opportunities && section.opportunities.length > 0) {
      children.push(new Paragraph({ text: 'Opportunities:', heading: HeadingLevel.HEADING_3 }));
      for (const opp of section.opportunities) {
        children.push(new Paragraph({
          text: opp,
          bullet: { level: 0 }
        }));
      }
    }
  }

  children.push(new Paragraph({ text: '' }));
}

const doc = new Document({
  sections: [{ children }]
});

const buffer = await Packer.toBuffer(doc);
const filename = targetMonth.slice(0, 7) + '_financial_summary.docx';

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(buffer),
  filename,
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
);

return [{
  json: {
    filename: filename,
    target_month: targetMonth,
    report_label: reportLabel,
    fiscal_year: $json.fiscal_year,
    raw_actuals: $json.raw_actuals,
    metrics: $json.metrics,
    claude_response: report
  },
  binary: { data: binaryData }
}];

const prevDocx = $('Generate DOCX').first().json;
const signedUrlResp = $('Create Signed URL').first().json;

const targetMonth = prevDocx.target_month;
const reportLabel = prevDocx.report_label;
const fiscalYear = prevDocx.fiscal_year;
const filename = prevDocx.filename;

// Derive quarter from target month
const monthNum = new Date(targetMonth + 'T00:00:00Z').getUTCMonth(); // 0-indexed
const quarter = 'Q' + (Math.floor(monthNum / 3) + 1);

const logEntry = {
  agent_name: 'financial_analyst',
  event_type: 'report_generated',
  summary: 'Financial summary report generated for ' + reportLabel,
  document_url: 'governance/financial/' + filename,
  data_snapshot: {
    raw_actuals: prevDocx.raw_actuals,
    calculated_metrics: prevDocx.metrics,
    report_label: reportLabel,
    target_month: targetMonth
  },
  quarter: quarter,
  fiscal_year: fiscalYear
};

// Build signed download URL
const signedPath = signedUrlResp.signedURL || signedUrlResp.signedUrl || '';
const downloadUrl = signedPath.startsWith('http') ? signedPath : ($env.SUPABASE_URL + '/storage/v1' + signedPath);

return [{
  json: {
    log_entry: logEntry,
    download_url: downloadUrl,
    report_label: reportLabel,
    target_month: targetMonth,
    email_summary: prevDocx.claude_response.email_summary,
    filename: filename
  }
}];

const prevData = $('Prepare Governance Log Entry').first().json;

const reportLabel = prevData.report_label;
const downloadUrl = prevData.download_url;
const emailSummary = prevData.email_summary;

const emailHtml = '<h2>Financial Summary: ' + reportLabel + '</h2>' +
  '<p>' + emailSummary + '</p>' +
  '<p><a href="' + downloadUrl + '" style="display:inline-block;padding:12px 24px;background-color:#2563eb;color:#ffffff;text-decoration:none;border-radius:6px;font-weight:bold;">Download Report (DOCX)</a></p>' +
  '<p style="color:#6b7280;font-size:12px;">This download link expires in 30 days. The report is also backed up to Google Drive.</p>';

return [{
  json: {
    from: 'Faith & Harmony <info@faithandharmonyllc.com>',
    to: $env.FOUNDER_EMAIL,
    subject: 'Financial Summary: ' + reportLabel,
    html: emailHtml
  }
}];

const targetMonth = $json.target_month || $('Validate Claude Response').first().json.target_month;
const reportLabel = $json.report_label || $('Validate Claude Response').first().json.report_label;
const fiscalYear = $json.fiscal_year || $('Validate Claude Response').first().json.fiscal_year;
const errorMsg = $('Validate Claude Response').first().json.error_message;

const monthNum = new Date(targetMonth + 'T00:00:00Z').getUTCMonth();
const quarter = 'Q' + (Math.floor(monthNum / 3) + 1);

const logEntry = {
  agent_name: 'financial_analyst',
  event_type: 'error',
  summary: 'Claude API response validation failed for ' + reportLabel + ': ' + errorMsg,
  data_snapshot: {
    target_month: targetMonth,
    error: errorMsg,
    reason: 'claude_response_invalid'
  },
  quarter: quarter,
  fiscal_year: fiscalYear
};

return [{ json: { log_entry: logEntry } }];
